public class UserContext {
    private static User cachedUser;
    public static User getCurrent() {
        if (cachedUser != null) {
            return cachedUser;
        }
        Cache.OrgPartition partition = Cache.Org.getPartition('local.userCache');
        User fromCache = (User) partition.get('current');
        if (fromCache != null) {
            cachedUser = fromCache;
            return cachedUser;
        }
        cachedUser = [
            SELECT Id, Name, Email
            FROM User
            WHERE Id = :UserInfo.getUserId()
        ];
        partition.put('current', cachedUser, 600);
        return cachedUser;
    }
}
